lang["#MOD_PCUTTER_BLADE_UNSTABLE_NAME"] = "Hoja Inestable de Cortador de Plasma"
lang["#MOD_PCUTTER_BLADE_HEAVY_NAME"] = "Hoja Pesada de Cortador de Plasma"
lang["#MOD_PCUTTER_BLADE_SUPERHEATED_NAME"] = "Hoja Sobrecalentada de Cortador de Plasma"
lang["#MOD_PCUTTER_BLADE_OVERCLOCK_NAME"] = "Hoja Overclockeada de Cortador de Plasma"
lang["#MOD_KNIFE_BLADE_SERRATED_NAME"] = "Hoja Serrada de Cuchillo de Combate"
lang["#MOD_CROWBAR_HEAD_SAW_NAME"] = "Cabeza de Sierra de Palanca"
lang["#MOD_CROWBAR_HANDLE_HANDMADE_NAME"] = "Empuñadura Artesanal de Palanca"
lang["#MOD_BBAT_HEAD_BARBED_NAME"] = "Alambre de Púas de Bate de Béisbol"
lang["#MOD_BBAT_HEAD_NAILS_NAME"] = "Clavos de Bate de Béisbol"
lang["#MOD_BBAT_HANDLE_TAPE_NAME"] = "Cinta de Mango de Bate de Béisbol"
lang["#MOD_BBAT_BODY_METAL_NAME"] = "Cuerpo de Aluminio de Bate de Béisbol"
lang["#MOD_MACHETE_BLADE_SERRATED_NAME"] = "Hoja Serrada de Machete"
lang["#MOD_PFIST_HEAD_REBAR_NAME"] = "Mod de Varilla de Puño de Fuerza"
lang["#MOD_SLEDGE_HEAD_CINDER_NAME"] = "Mod de Bloque de Hormigón de Martillo"
lang["#MOD_SUPERSLEDGE_HEAD_HEATED_NAME"] = "Mod de Bobina Calefactora de Super Martillo"
-- Descripciones
lang["#MOD_PCUTTER_BLADE_UNSTABLE_DESC"] = "Un conjunto de proyectores inestables para el Cortador de Plasma.\n\nLos proyectores mal protegidos crean una hoja más fuerte, pero temperamental.\n\nPor favor, no lo dejes caer."
lang["#MOD_PCUTTER_BLADE_HEAVY_DESC"] = "Un conjunto de proyectores de servicio pesado para el Cortador de Plasma.\n\nIdeal para usos industriales, como desmantelar coches viejos o cortar extremidades y armaduras pesadas."
lang["#MOD_PCUTTER_BLADE_SUPERHEATED_DESC"] = "Un conjunto de proyectores enfocados para el Cortador de Plasma.\n\nAumentar el enfoque del haz aumenta su temperatura y, por lo tanto, su letalidad."
lang["#MOD_PCUTTER_BLADE_OVERCLOCK_DESC"] = "Un conjunto de proyectores optimizados para el Cortador de Plasma.\n\nModificado para obtener un poco de energía extra del cortador sin peligro adicional. Una mejora en todos los sentidos."
lang["#MOD_KNIFE_BLADE_SERRATED_DESC"] = "Una modificación de hoja para el cuchillo de combate. Duele muchísimo más que te apuñale algo así. También muy duradero."
lang["#MOD_CROWBAR_HEAD_SAW_DESC"] = "Una modificación que se puede acoplar a la cabeza de una palanca. Simplemente la convertirá de un arma contundente a un arma afilada. Sufre más condición por ser usada."
lang["#MOD_CROWBAR_HANDLE_HANDMADE_DESC"] = "Una modificación que se puede acoplar al mango de una palanca. Hecha a mano, y hace que sea mucho más fácil de agarrar mientras se balancea."
lang["#MOD_BBAT_HEAD_BARBED_DESC"] = "Una modificación que se puede acoplar a la cabeza de un bate de béisbol. Es alambre de púas, definitivamente dolerá al primer objetivo que golpees con él."
lang["#MOD_BBAT_HEAD_NAILS_DESC"] = "Una modificación que se puede acoplar a la cabeza de un bate de béisbol. Clásico, clavos en un bate de béisbol."
lang["#MOD_BBAT_HANDLE_TAPE_DESC"] = "Una modificación que se puede acoplar al mango de un bate de béisbol. Facilita mucho el agarre del arma, especialmente al balancearla."
lang["#MOD_BBAT_BODY_METAL_DESC"] = "Un nuevo cuerpo para el bate de béisbol. Aunque estaban prohibidos en las grandes ligas, los bates de aluminio eran comunes para uso recreativo. Más ligeros y duraderos que los bates de madera."
lang["#MOD_MACHETE_BLADE_SERRATED_DESC"] = "Una modificación de hoja para el machete. Balancear esto contra alguien podría doler mucho más de lo habitual."
lang["#MOD_PFIST_HEAD_REBAR_DESC"] = "Una modificación de cabeza para el puño de fuerza. Horriblemente acoplada, pero esto atravesará a un enemigo si lo golpeas con él."
lang["#MOD_SLEDGE_HEAD_CINDER_DESC"] = "Una modificación de bloque de hormigón para el martillo, ¿por qué no? ¿A quién le importan sus brazos de todos modos si puedes aplastarle la cabeza a alguien como una sandía de un solo golpe?"
lang["#MOD_SUPERSLEDGE_HEAD_HEATED_DESC"] = "Una modificación de bobina calefactora para el Super Martillo. Solo ten cuidado de no tocar las partes brillantes."


RELOADSCHEMA = true
